import 'package:flutter_test/flutter_test.dart';\nimport 'package:chefmind_ai_app/features/recipes/domain/entities/recipe_ingredient.dart';\nimport 'package:chefmind_ai_app/features/recipes/domain/entities/ingredient.dart';\n\nvoid main() {\n  group('RecipeIngredient Entity Tests', () {\n    late RecipeIngredient testRecipeIngredient;\n    late NutritionInfo testNutrition;\n\n    setUp(() {\n      testNutrition = const NutritionInfo(\n        calories: 100.0,\n        protein: 2.0,\n        carbohydrates: 20.0,\n        fat: 1.0,\n      );\n\n      testRecipeIngredient = RecipeIngredient(\n        ingredientId: 'flour-001',\n        name: 'All-Purpose Flour',\n        quantity: 2.0,\n        unit: 'cups',\n        preparation: 'sifted',\n        notes: 'Use room temperature flour for best results',\n        isOptional: false,\n        isGarnish: false,\n        displayOrder: 1,\n        category: 'grains',\n        substitutes: ['whole wheat flour', 'cake flour'],\n        nutritionInfo: testNutrition,\n        estimatedCost: 1.50,\n        seasonality: 'year-round',\n        availability: AvailabilityStatus.available,\n      );\n    });\n\n    test('should create recipe ingredient with all properties', () {\n      expect(testRecipeIngredient.ingredientId, 'flour-001');\n      expect(testRecipeIngredient.name, 'All-Purpose Flour');\n      expect(testRecipeIngredient.quantity, 2.0);\n      expect(testRecipeIngredient.unit, 'cups');\n      expect(testRecipeIngredient.preparation, 'sifted');\n      expect(testRecipeIngredient.notes, 'Use room temperature flour for best results');\n      expect(testRecipeIngredient.isOptional, false);\n      expect(testRecipeIngredient.isGarnish, false);\n      expect(testRecipeIngredient.displayOrder, 1);\n      expect(testRecipeIngredient.substitutes.length, 2);\n    });\n\n    test('should have correct default values', () {\n      const minimalIngredient = RecipeIngredient(\n        ingredientId: 'ing-001',\n        name: 'Test Ingredient',\n        quantity: 1.0,\n        unit: 'piece',\n      );\n\n      expect(minimalIngredient.isOptional, false);\n      expect(minimalIngredient.isGarnish, false);\n      expect(minimalIngredient.displayOrder, 1);\n      expect(minimalIngredient.substitutes, isEmpty);\n      expect(minimalIngredient.estimatedCost, 0.0);\n      expect(minimalIngredient.availability, AvailabilityStatus.available);\n    });\n\n    test('should serialize to and from JSON correctly', () {\n      final json = testRecipeIngredient.toJson();\n      final deserialized = RecipeIngredient.fromJson(json);\n\n      expect(deserialized.ingredientId, testRecipeIngredient.ingredientId);\n      expect(deserialized.name, testRecipeIngredient.name);\n      expect(deserialized.quantity, testRecipeIngredient.quantity);\n      expect(deserialized.unit, testRecipeIngredient.unit);\n      expect(deserialized.preparation, testRecipeIngredient.preparation);\n      expect(deserialized.notes, testRecipeIngredient.notes);\n      expect(deserialized.availability, testRecipeIngredient.availability);\n    });\n\n    test('should handle copyWith correctly', () {\n      final updated = testRecipeIngredient.copyWith(\n        quantity: 3.0,\n        unit: 'kg',\n        isOptional: true,\n        estimatedCost: 2.00,\n      );\n\n      expect(updated.quantity, 3.0);\n      expect(updated.unit, 'kg');\n      expect(updated.isOptional, true);\n      expect(updated.estimatedCost, 2.00);\n      // Other fields should remain the same\n      expect(updated.ingredientId, testRecipeIngredient.ingredientId);\n      expect(updated.name, testRecipeIngredient.name);\n      expect(updated.preparation, testRecipeIngredient.preparation);\n    });\n\n    test('should handle nutrition information correctly', () {\n      expect(testRecipeIngredient.nutritionInfo?.calories, 100.0);\n      expect(testRecipeIngredient.nutritionInfo?.protein, 2.0);\n      expect(testRecipeIngredient.nutritionInfo?.carbohydrates, 20.0);\n      expect(testRecipeIngredient.nutritionInfo?.fat, 1.0);\n    });\n\n    test('should handle optional and garnish ingredients', () {\n      const optionalIngredient = RecipeIngredient(\n        ingredientId: 'parsley-001',\n        name: 'Fresh Parsley',\n        quantity: 2.0,\n        unit: 'tbsp',\n        isOptional: true,\n        isGarnish: true,\n        displayOrder: 10,\n      );\n\n      expect(optionalIngredient.isOptional, true);\n      expect(optionalIngredient.isGarnish, true);\n      expect(optionalIngredient.displayOrder, 10);\n    });\n\n    test('should handle different availability statuses', () {\n      const seasonalIngredient = RecipeIngredient(\n        ingredientId: 'strawberry-001',\n        name: 'Fresh Strawberries',\n        quantity: 1.0,\n        unit: 'cup',\n        availability: AvailabilityStatus.seasonal,\n        seasonality: 'spring-summer',\n      );\n\n      const expensiveIngredient = RecipeIngredient(\n        ingredientId: 'truffle-001',\n        name: 'Black Truffle',\n        quantity: 0.5,\n        unit: 'oz',\n        availability: AvailabilityStatus.expensive,\n        estimatedCost: 50.00,\n      );\n\n      expect(seasonalIngredient.availability, AvailabilityStatus.seasonal);\n      expect(seasonalIngredient.seasonality, 'spring-summer');\n      expect(expensiveIngredient.availability, AvailabilityStatus.expensive);\n      expect(expensiveIngredient.estimatedCost, 50.00);\n    });\n  });\n\n  group('MeasurementUnit Enum Tests', () {\n    test('should have volume units', () {\n      expect(MeasurementUnit.values, contains(MeasurementUnit.milliliters));\n      expect(MeasurementUnit.values, contains(MeasurementUnit.liters));\n      expect(MeasurementUnit.values, contains(MeasurementUnit.teaspoons));\n      expect(MeasurementUnit.values, contains(MeasurementUnit.tablespoons));\n      expect(MeasurementUnit.values, contains(MeasurementUnit.cups));\n      expect(MeasurementUnit.values, contains(MeasurementUnit.fluidOunces));\n    });\n\n    test('should have weight units', () {\n      expect(MeasurementUnit.values, contains(MeasurementUnit.grams));\n      expect(MeasurementUnit.values, contains(MeasurementUnit.kilograms));\n      expect(MeasurementUnit.values, contains(MeasurementUnit.ounces));\n      expect(MeasurementUnit.values, contains(MeasurementUnit.pounds));\n      expect(MeasurementUnit.values, contains(MeasurementUnit.milligrams));\n    });\n\n    test('should have count units', () {\n      expect(MeasurementUnit.values, contains(MeasurementUnit.pieces));\n      expect(MeasurementUnit.values, contains(MeasurementUnit.items));\n      expect(MeasurementUnit.values, contains(MeasurementUnit.cloves));\n      expect(MeasurementUnit.values, contains(MeasurementUnit.slices));\n      expect(MeasurementUnit.values, contains(MeasurementUnit.bunches));\n    });\n\n    test('should have special units', () {\n      expect(MeasurementUnit.values, contains(MeasurementUnit.pinch));\n      expect(MeasurementUnit.values, contains(MeasurementUnit.dash));\n      expect(MeasurementUnit.values, contains(MeasurementUnit.splash));\n      expect(MeasurementUnit.values, contains(MeasurementUnit.toTaste));\n    });\n  });\n\n  group('PreparationMethod Enum Tests', () {\n    test('should have cutting methods', () {\n      expect(PreparationMethod.values, contains(PreparationMethod.chopped));\n      expect(PreparationMethod.values, contains(PreparationMethod.diced));\n      expect(PreparationMethod.values, contains(PreparationMethod.minced));\n      expect(PreparationMethod.values, contains(PreparationMethod.sliced));\n      expect(PreparationMethod.values, contains(PreparationMethod.julienned));\n    });\n\n    test('should have processing methods', () {\n      expect(PreparationMethod.values, contains(PreparationMethod.grated));\n      expect(PreparationMethod.values, contains(PreparationMethod.shredded));\n      expect(PreparationMethod.values, contains(PreparationMethod.crushed));\n      expect(PreparationMethod.values, contains(PreparationMethod.ground));\n      expect(PreparationMethod.values, contains(PreparationMethod.mashed));\n      expect(PreparationMethod.values, contains(PreparationMethod.pureed));\n    });\n\n    test('should have preparation states', () {\n      expect(PreparationMethod.values, contains(PreparationMethod.peeled));\n      expect(PreparationMethod.values, contains(PreparationMethod.seeded));\n      expect(PreparationMethod.values, contains(PreparationMethod.trimmed));\n      expect(PreparationMethod.values, contains(PreparationMethod.cleaned));\n      expect(PreparationMethod.values, contains(PreparationMethod.fresh));\n      expect(PreparationMethod.values, contains(PreparationMethod.frozen));\n    });\n  });\n\n  group('AvailabilityStatus Enum Tests', () {\n    test('should have all availability statuses', () {\n      expect(AvailabilityStatus.values.length, 5);\n      expect(AvailabilityStatus.values, contains(AvailabilityStatus.available));\n      expect(AvailabilityStatus.values, contains(AvailabilityStatus.limited));\n      expect(AvailabilityStatus.values, contains(AvailabilityStatus.seasonal));\n      expect(AvailabilityStatus.values, contains(AvailabilityStatus.unavailable));\n      expect(AvailabilityStatus.values, contains(AvailabilityStatus.expensive));\n    });\n  });\n\n  group('RecipeIngredient Edge Cases', () {\n    test('should handle fractional quantities', () {\n      const ingredient = RecipeIngredient(\n        ingredientId: 'egg-001',\n        name: 'Large Egg',\n        quantity: 0.5,\n        unit: 'piece',\n        notes: 'Use half an egg (beat and measure)',\n      );\n\n      expect(ingredient.quantity, 0.5);\n      expect(ingredient.notes, contains('half an egg'));\n    });\n\n    test('should handle very small quantities', () {\n      const ingredient = RecipeIngredient(\n        ingredientId: 'salt-001',\n        name: 'Sea Salt',\n        quantity: 0.25,\n        unit: 'tsp',\n        preparation: 'fine',\n      );\n\n      expect(ingredient.quantity, 0.25);\n      expect(ingredient.unit, 'tsp');\n    });\n\n    test('should handle large quantities for batch cooking', () {\n      const ingredient = RecipeIngredient(\n        ingredientId: 'flour-001',\n        name: 'Bread Flour',\n        quantity: 50.0,\n        unit: 'lb',\n        notes: 'For commercial batch',\n      );\n\n      expect(ingredient.quantity, 50.0);\n      expect(ingredient.unit, 'lb');\n    });\n\n    test('should handle ingredients with multiple substitutes', () {\n      const ingredient = RecipeIngredient(\n        ingredientId: 'butter-001',\n        name: 'Unsalted Butter',\n        quantity: 1.0,\n        unit: 'cup',\n        substitutes: [\n          'margarine (1:1 ratio)',\n          'coconut oil (3/4 cup)',\n          'vegetable oil (3/4 cup)',\n          'applesauce (1/2 cup)',\n        ],\n      );\n\n      expect(ingredient.substitutes.length, 4);\n      expect(ingredient.substitutes.first, contains('margarine'));\n      expect(ingredient.substitutes.last, contains('applesauce'));\n    });\n\n    test('should handle ingredients with complex preparation instructions', () {\n      const ingredient = RecipeIngredient(\n        ingredientId: 'chicken-001',\n        name: 'Chicken Breast',\n        quantity: 2.0,\n        unit: 'lb',\n        preparation: 'boneless, skinless, pounded to 1/2 inch thickness',\n        notes: 'Let come to room temperature before cooking',\n      );\n\n      expect(ingredient.preparation, contains('boneless'));\n      expect(ingredient.preparation, contains('pounded'));\n      expect(ingredient.notes, contains('room temperature'));\n    });\n\n    test('should handle seasonal availability with specific notes', () {\n      const ingredient = RecipeIngredient(\n        ingredientId: 'asparagus-001',\n        name: 'Fresh Asparagus',\n        quantity: 1.0,\n        unit: 'lb',\n        availability: AvailabilityStatus.seasonal,\n        seasonality: 'spring (March-June)',\n        notes: 'Choose firm spears with tight tips',\n      );\n\n      expect(ingredient.availability, AvailabilityStatus.seasonal);\n      expect(ingredient.seasonality, contains('spring'));\n      expect(ingredient.notes, contains('firm spears'));\n    });\n  });\n}\n